css:
:root {
  --beige: #e9dec8;
  --beige-dark: #d6c4a1;
  --manila: #e2cb9e;
  --manila-dark: #c8ad78;
  --panel: #f6eedf;
  --text: #1f1f1f;
  --navy: #0d3b66;
  --navy-hover: #0a2d4d;
  --danger: #8b2222;
  --shadow: rgba(0, 0, 0, 0.12);
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  min-height: 100vh;
  font-family: "Trebuchet MS", "Segoe UI", sans-serif;
  color: var(--text);
  background:
    radial-gradient(circle at 15% 15%, #f5ecdc 0%, transparent 35%),
    radial-gradient(circle at 85% 80%, #e2d2b3 0%, transparent 30%),
    var(--beige);
}

.page {
  min-height: 100vh;
  display: grid;
  grid-template-columns: 1fr 1fr;
}

.brand-side {
  padding: 2rem;
  display: flex;
  align-items: flex-start;
  justify-content: flex-start;
  background: linear-gradient(180deg, var(--beige), var(--beige-dark));
  border-right: 1px solid rgba(0, 0, 0, 0.08);
}

.brand {
  font-size: clamp(2rem, 5vw, 3.75rem);
  font-weight: 700;
  letter-spacing: 0.08em;
}

.login-side {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 2rem;
  background: rgba(255, 255, 255, 0.28);
}

.login-card {
  width: min(400px, 100%);
  background: var(--panel);
  border: 1px solid rgba(0, 0, 0, 0.1);
  border-radius: 14px;
  padding: 1.5rem;
  box-shadow: 0 10px 25px var(--shadow);
}

.field {
  margin-bottom: 1rem;
}

label {
  display: block;
  margin-bottom: 0.4rem;
  font-weight: 600;
}

input {
  width: 100%;
  padding: 0.7rem 0.8rem;
  border-radius: 10px;
  border: 1px solid #b9a787;
  background: #fffaf1;
  color: var(--text);
  font-size: 1rem;
}

input:focus {
  outline: 2px solid #bca97f;
  outline-offset: 2px;
}

button {
  width: 100%;
  padding: 0.78rem 1rem;
  border: none;
  border-radius: 10px;
  font-size: 1rem;
  font-weight: 700;
  cursor: pointer;
  background: var(--navy);
  color: #000;
  transition: background 0.2s ease;
}

button:hover {
  background: var(--navy-hover);
}

.message {
  margin-top: 0.9rem;
  min-height: 1.25rem;
  font-size: 0.95rem;
}

.hidden {
  display: none;
}

.app-shell {
  min-height: 100vh;
  padding: clamp(1rem, 2.5vw, 2rem);
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.app-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-bottom: 0.5rem;
  border-bottom: 1px solid rgba(0, 0, 0, 0.1);
}

.welcome {
  font-size: 1rem;
  opacity: 0.9;
}

.folder {
  position: relative;
  flex: 1;
  background: linear-gradient(180deg, var(--manila), #dcc08d);
  border: 1px solid #b08f58;
  border-radius: 12px;
  box-shadow: 0 12px 28px var(--shadow);
  padding: 3.2rem 1rem 1rem;
  overflow: hidden;
}

.tabs {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  display: flex;
  gap: 0.4rem;
  padding: 0.6rem 0.7rem 0;
  overflow-x: auto;
  scrollbar-width: thin;
}

.tab {
  border: 1px solid #a6864f;
  border-bottom: none;
  background: linear-gradient(180deg, #f2ddb7, #dfc18a);
  color: #2a1e10;
  padding: 0.55rem 0.8rem;
  border-top-left-radius: 8px;
  border-top-right-radius: 8px;
  white-space: nowrap;
  font-size: 0.92rem;
  font-weight: 700;
  cursor: pointer;
  flex: 0 0 auto;
}

.tab.active {
  background: #f5e3c0;
  transform: translateY(1px);
  box-shadow: 0 -2px 0 rgba(255, 255, 255, 0.35) inset;
}

.folder-content {
  height: 100%;
  min-height: 56vh;
  background: #f5e3c0;
  border: 1px solid #a6864f;
  border-radius: 8px;
  padding: 1rem;
}

.panel {
  display: none;
  height: 100%;
}

.panel.active {
  display: block;
}

.panel h2 {
  margin-bottom: 0.6rem;
  font-size: 1.2rem;
}

.panel p {
  line-height: 1.5;
  max-width: 68ch;
}

@media (max-width: 850px) {
  .page {
    grid-template-columns: 1fr;
  }

  .brand-side {
    min-height: 26vh;
  }

  .login-side {
    min-height: 74vh;
  }

  .folder {
    padding-top: 3.45rem;
  }

  .folder-content {
    min-height: 60vh;
  }
}
